<script lang="ts">
  // $types is generated by svelte-kit sync; import if available, otherwise use inline shape
  import type { FulfillmentStatus, FulfillmentTask, StatusUpdate, Departure } from '$lib/features/s3-ops/types';
  import FulfillmentStatusBadge from '$lib/components/ops/FulfillmentStatusBadge.svelte';
  import { updateFulfillmentStatus } from '$lib/features/s3-ops/ops-api';

  interface PageData {
    tasks: FulfillmentTask[];
    total: number;
    departures: Departure[];
    error: string | null;
  }

  let { data }: { data: PageData } = $props();

  // --- local reactive state ---
  let tasks = $state<FulfillmentTask[]>(data.tasks ?? []);
  let statusFilter = $state<FulfillmentStatus | 'all'>('all');
  let departureFilter = $state<string>('all');
  let searchQuery = $state('');

  // --- update status modal state ---
  let modalOpen = $state(false);
  let modalTask = $state<FulfillmentTask | null>(null);
  let modalStatus = $state<FulfillmentStatus>('queued');
  let modalTracking = $state('');
  let modalSaving = $state(false);
  let modalError = $state('');

  const STATUS_OPTIONS: Array<{ value: FulfillmentStatus | 'all'; label: string }> = [
    { value: 'all', label: 'All Status' },
    { value: 'queued', label: 'Queued' },
    { value: 'processing', label: 'Processing' },
    { value: 'shipped', label: 'Shipped' },
    { value: 'delivered', label: 'Delivered' },
    { value: 'cancelled', label: 'Cancelled' }
  ];

  const FULFILLMENT_STATUSES: FulfillmentStatus[] = [
    'queued',
    'processing',
    'shipped',
    'delivered',
    'cancelled'
  ];

  // --- derived filtered list ---
  const filteredTasks = $derived(
    tasks.filter((t) => {
      const matchStatus = statusFilter === 'all' || t.fulfillment_status === statusFilter;

      const matchDeparture =
        departureFilter === 'all' ||
        (() => {
          const deps = (data.departures ?? []) as Departure[];
          const dep = deps.find((d) => d.id === departureFilter);
          return dep ? t.departure_date === dep.departure_date : true;
        })();

      const matchSearch =
        !searchQuery ||
        t.booking_code.toLowerCase().includes(searchQuery.toLowerCase()) ||
        t.jamaah_name.toLowerCase().includes(searchQuery.toLowerCase());

      return matchStatus && matchDeparture && matchSearch;
    })
  );

  // --- summary counts ---
  const summaryCount = $derived(
    FULFILLMENT_STATUSES.reduce(
      (acc, s) => {
        acc[s] = tasks.filter((t) => t.fulfillment_status === s).length;
        return acc;
      },
      {} as Record<FulfillmentStatus, number>
    )
  );

  // --- helpers ---
  function formatDate(iso: string): string {
    try {
      return new Date(iso).toLocaleDateString('id-ID', {
        day: '2-digit',
        month: 'short',
        year: 'numeric'
      });
    } catch {
      return iso;
    }
  }

  function openUpdateModal(task: FulfillmentTask) {
    modalTask = task;
    modalStatus = task.fulfillment_status;
    modalTracking = task.tracking_number ?? '';
    modalError = '';
    modalOpen = true;
  }

  function closeModal() {
    modalOpen = false;
    modalTask = null;
    modalError = '';
  }

  async function saveStatus() {
    if (!modalTask) return;
    modalSaving = true;
    modalError = '';
    try {
      const update: StatusUpdate = { status: modalStatus };
      if (modalTracking.trim()) update.tracking_number = modalTracking.trim();
      const updated = await updateFulfillmentStatus(modalTask.id, update);
      tasks = tasks.map((t) => (t.id === updated.id ? updated : t));
      closeModal();
    } catch (err) {
      modalError = err instanceof Error ? err.message : 'Gagal menyimpan perubahan.';
    } finally {
      modalSaving = false;
    }
  }
</script>

