    <!-- Summary bar -->
    <div class="summary-bar">
      {#each FULFILLMENT_STATUSES as s}
        <button
          type="button"
          class="summary-chip summary-chip--{s}"
          class:active={statusFilter === s}
          onclick={() => { statusFilter = statusFilter === s ? 'all' : s; }}
        >
