          />
        </div>
      </div>

      {#if statusFilter !== 'all' || departureFilter !== 'all' || searchQuery}
        <button
          type="button"
          class="clear-btn"
          onclick={() => { statusFilter = 'all'; departureFilter = 'all'; searchQuery = ''; }}
