        </button>
      {/if}
    </div>

    {#if data.error}
      <div class="error-banner">
        <span class="material-symbols-outlined">error</span>
        {data.error}
      </div>
    {/if}

    <!-- Table -->
    <div class="panel">
      <div class="table-wrap">
        {#if filteredTasks.length === 0}
