      <select id="modal-status" class="modal-select" bind:value={modalStatus}>
        {#each FULFILLMENT_STATUSES as s}
          <option value={s}>{s.charAt(0).toUpperCase() + s.slice(1)}</option>
        {/each}
      </select>

